import React, { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { analyzeImage } from './api';
import { ClipLoader } from 'react-spinners';

export default function UploadImage() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [age, setAge] = useState('');
  const [sex, setSex] = useState('');

  // File handling and validation
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file?.type.startsWith('image/')) {
      setError('Please upload a medical image (JPEG/PNG/DICOM)');
      return;
    }
    setFile(file);
    setError('');
  };

  // Analysis submission
  const handleAnalyze = async () => {
    if (!file || !age || !sex) {
      setError('Please complete all required fields');
      return;
    }

    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('age', age);
      formData.append('sex', sex);

      const { analysis } = await analyzeImage(formData);
      setReport(analysis);
    } catch (err) {
      setError(err.message || 'Failed to analyze medical image');
    } finally {
      setLoading(false);
    }
  };

  // Markdown processing with certainty detection
  const MedicalMarkdown = ({ content }) => {
    const extractText = (children) => {
      return React.Children.toArray(children)
        .map(child => {
          if (typeof child === 'string') return child;
          if (child?.props?.children) return extractText(child.props.children);
          return '';
        })
        .join(' ')
        .replace(/\s+/g, ' ')
        .trim();
    };

    return (
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        components={{
          strong({ children }) {
            const text = extractText(children);
            const match = text.match(/^(.*?)\s*\(Certainty:\s*(\d+%)\)$/i);

            return match ? (
              <span className="font-semibold text-medical-dark dark:text-medical-light">
                {match[1]}
                <span className="ml-1.5 text-diagnostic-blue-600 dark:text-diagnostic-blue-400">
                  (Certainty: {match[2]})
                </span>
              </span>
            ) : (
              <strong className="text-diagnostic-red">{children}</strong>
            );
          },
          ul: ({ children }) => (
            <ul className="ml-6 list-disc space-y-2 marker:text-diagnostic-blue-400">
              {children}
            </ul>
          ),
          li: ({ children }) => (
            <li className="text-medical-dark dark:text-medical-light/90">
              {children}
            </li>
          ),
          h3: ({ children }) => (
            <h3 className="mt-8 mb-4 text-xl font-bold border-b pb-2 text-diagnostic-blue-800 dark:text-diagnostic-blue-200 border-diagnostic-blue-200 dark:border-diagnostic-blue-800">
              {children}
            </h3>
          )
        }}
      >
        {content}
      </ReactMarkdown>
    );
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-white dark:bg-medical-dark rounded-xl shadow-medical dark:shadow-medical-dark">
      <h1 className="text-3xl font-bold text-center mb-8 text-diagnostic-blue-800 dark:text-diagnostic-blue-200">
        Medical Imaging Analyzer
      </h1>

      <div className="space-y-6">
        {/* File Upload */}
        <div className="space-y-3">
          <label className="block text-lg font-medium text-diagnostic-blue-700 dark:text-diagnostic-blue-300">
            Upload Medical Scan
          </label>
          <input
            type="file"
            onChange={handleFileChange}
            accept="image/*,.dcm"
            className="block w-full file:mr-4 file:py-3 file:px-6 file:border-0 file:rounded-lg file:bg-diagnostic-blue-600 file:text-white hover:file:bg-diagnostic-blue-700 dark:file:bg-diagnostic-blue-800 dark:hover:file:bg-diagnostic-blue-900 transition-colors"
          />
        </div>

        {/* Patient Info */}
        <div className="grid grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-diagnostic-blue-700 dark:text-diagnostic-blue-300">
              Patient Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/\D/g, ''))}
              className="w-full p-3 rounded-lg border-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800 bg-white dark:bg-medical-dark focus:ring-2 focus:ring-diagnostic-blue-500"
              placeholder="Age"
              min="0"
              max="120"
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-medium text-diagnostic-blue-700 dark:text-diagnostic-blue-300">
              Biological Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-3 rounded-lg border-2 border-diagnostic-blue-200 dark:border-diagnostic-blue-800 bg-white dark:bg-medical-dark focus:ring-2 focus:ring-diagnostic-blue-500"
            >
              <option value="">Select</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analysis Button */}
        <button
          onClick={handleAnalyze}
          disabled={loading}
          className={`w-full py-4 px-8 rounded-lg font-bold text-white transition-colors ${
            loading ? 'bg-gray-400' : 'bg-diagnostic-blue-600 hover:bg-diagnostic-blue-700 dark:bg-diagnostic-blue-800 dark:hover:bg-diagnostic-blue-900'
          }`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-2">
              <ClipLoader color="#ffffff" size={24} />
              <span>Analyzing...</span>
            </div>
          ) : (
            'Analyze Medical Image'
          )}
        </button>

        {/* Error Display */}
        {error && (
          <div className="p-4 bg-red-100 dark:bg-red-900/50 rounded-lg border border-red-200 dark:border-red-800 text-red-700 dark:text-red-200 flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            {error}
          </div>
        )}

        {/* Analysis Report */}
        {report && (
          <div className="mt-8 p-6 bg-white dark:bg-medical-dark rounded-xl shadow-medical border-2 border-diagnostic-blue-100 dark:border-diagnostic-blue-800">
            <h2 className="text-2xl font-bold mb-6 text-diagnostic-blue-800 dark:text-diagnostic-blue-200">
              Diagnostic Report
            </h2>
            <div className="prose medical-prose dark:medical-prose-invert max-w-none">
              <MedicalMarkdown content={report} />
            </div>
            <div className="mt-6 p-4 bg-yellow-100 dark:bg-yellow-900/50 rounded-lg border border-yellow-200 dark:border-yellow-800 flex items-start gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0 text-yellow-600 dark:text-yellow-300" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
              </svg>
              <p className="text-sm text-yellow-800 dark:text-yellow-200">
                This AI-generated analysis requires clinical validation by a board-certified radiologist.
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
